    // MARK: - Core Request Method
    
    private func performRequest<T: Decodable>(
        endpoint: APIEndpoint,
        body: Encodable? = nil,
        requiresAuth: Bool,
        isRetry: Bool = false
    ) async throws -> T {
        let request = try buildRequest(
            endpoint: endpoint,
            body: body,
